from elasticsearch import Elasticsearch

def run_script(es, index, script_code):
    try:
        result = es.search(
            index=index,
            body={
                'size': 0,
                'aggs': {
                    'script_result': {
                        'script': script_code
                    }
                }
            },
            doc_type='*_doc'
        )
        return result['aggregations']['script_result']['value']
    except Exception as e:
        print(f"Error executing script: {e}")

